,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select TICKET_NUM,',
'       NO_URUT_FORM,',
'       TGL_PERMINTAAN,',
'       PEMINTA,',
'       NIK_PEMINTA,',
'       JABATAN_PEMINTA,',
'       LOKASI_PEMINTA,',
'       PENGGUNA,',
'       NIK_PENGGUNA,',
