'       EMAIL_APPROVER1,',
'       APPROVER2,',
'       EMAIL_APPROVER2,status,updated_by',
'  from NTI_FORM_REQUEST_IT_TBL',
' where  id_1 = (select param_value ',
'  from apex_task_parameters ',
' where task_id= :P9_TASK_ID ',
'   and param_static_id=''ID'')',
' union',
'select TICKET_NUM,',
'       NO_URUT_FORM,',
'       TGL_PERMINTAAN,',
'       PEMINTA,',
