,p_region_template_options=>'#DEFAULT#:t-ContentBlock--h3:t-ContentBlock--lightBG:margin-top-md'
,p_component_template_options=>'#DEFAULT#:t-AVPList--leftAligned'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select PEMINTA,',
'       JABATAN_PEMINTA,',
'       LOKASI_PEMINTA,',
'       PENGGUNA,',
'       JABATAN_PENGGUNA,',
'       LOKASI_PENGGUNA,',
'       MANDATORY_HD_SOFT,',
'       OPTIONAL_SOFT,',
'       OPTIONAL_HD,',
'       KETERANGAN,',
'       status,',
'       updated_by',
'  from FORM_REQUEST_IT_TRX',
' where req_id = (select param_value ',
'  from apex_task_parameters ',
' where task_id= :P13_TASK_ID ',
'   and param_static_id=''REQ_ID'')',
' union',
'select PEMINTA,',
'       JABATAN_PEMINTA,',
'       LOKASI_PEMINTA,',
'       PENGGUNA,',
'       JABATAN_PENGGUNA,',
'       LOKASI_PENGGUNA,',
'       MANDATORY_HD_SOFT,',
'       OPTIONAL_SOFT,',
'       OPTIONAL_HD,',
'       KETERANGAN,',
'       status,',
'       updated_by',
'  from FORM_REQUEST_IT_TRX ',
' where req_id = :P13_TASK_ID;'))
,p_ajax_enabled=>'Y'
,p_ajax_items_to_submit=>'P13_TASK_ID'
,p_lazy_loading=>false
,p_query_row_template=>2101991776017792140
